#include <vector>
#include <queue>
#include <tuple>
#include <climits>

using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 0 || n == 0) return 0;

    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(2, LLONG_MAX)));
    priority_queue<tuple<long long, long long, long long, long long>, 
                   vector<tuple<long long, long long, long long, long long>>, 
                   greater<tuple<long long, long long, long long, long long>>> pq;

    // Initial state: (time % 2, cost, i, j)
    // Start at (0, 0) at time 1 (odd)
    dist[0][0][1] = (0 + 1) * (0 + 1); // entry cost at (0,0)
    pq.push({dist[0][0][1], 1, 0, 0});

    int dirs[2][2] = {{0, 1}, {1, 0}}; // right and down

    while (!pq.empty()) {
        auto [current_cost, time, i, j] = pq.top();
        pq.pop();

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (time % 2 == 1) { // odd time: move
            for (auto &dir : dirs) {
                long long ni = i + dir[0];
                long long nj = j + dir[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long long new_cost = current_cost + (ni + 1) * (nj + 1);
                    long long new_time = time + 1;
                    if (new_cost < dist[ni][nj][new_time % 2]) {
                        dist[ni][nj][new_time % 2] = new_cost;
                        pq.push({new_cost, new_time, ni, nj});
                    }
                }
            }
        } else { // even time: wait
            long long new_cost = current_cost + waitCost[i][j];
            long long new_time = time + 1;
            if (new_cost < dist[i][j][new_time % 2]) {
                dist[i][j][new_time % 2] = new_cost;
                pq.push({new_cost, new_time, i, j});
            }
        }
    }

    return -1; // unreachable
}

